import subprocess
import json
import sys

PROFILE = '{profile}'

def aws_cmd(service, action, extra_args=None):
    cmd = ['aws', service, action, '--output', 'json']
    if PROFILE: cmd.extend(['--profile', PROFILE])
    if extra_args: cmd.extend(extra_args)
    try:
        result = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        if result.returncode == 0:
            return json.loads(result.stdout)
    except: pass
    return None

print('=== AWS IAM Enumerator ===')

# Get caller identity
identity = aws_cmd('sts', 'get-caller-identity')
if identity:
    print(f'Account: {identity.get("Account")}')
    print(f'ARN: {identity.get("Arn")}')
else:
    print('Error: Cannot get identity (check credentials)'); sys.exit(1)

# List users
users = aws_cmd('iam', 'list-users')
if users:
    print(f'\nIAM Users: {len(users.get("Users", []))}')
    for u in users['Users'][:20]:
        print(f'  {u["UserName"]:30s} Created: {str(u.get("CreateDate",""))[:10]}')

# List roles
roles = aws_cmd('iam', 'list-roles')
if roles:
    print(f'\nIAM Roles: {len(roles.get("Roles", []))}')
    for r in roles['Roles'][:10]:
        print(f'  {r["RoleName"]}')

# Check S3 buckets
buckets = aws_cmd('s3api', 'list-buckets')
if buckets:
    print(f'\nS3 Buckets: {len(buckets.get("Buckets", []))}')
    for b in buckets['Buckets'][:10]:
        print(f'  {b["Name"]}')

