import os
import sys
import json

def check_container():
    indicators = []
    # Check if in container
    in_container = False
    if os.path.exists('/.dockerenv'):
        indicators.append('Docker container detected (/.dockerenv)')
        in_container = True
    try:
        with open('/proc/1/cgroup', 'r') as f:
            cgroup = f.read()
        if 'docker' in cgroup or 'kubepods' in cgroup:
            indicators.append('Container cgroup detected')
            in_container = True
    except: pass
    if not in_container:
        print('Not running in a container')
        return indicators

    # Check escape vectors
    # Docker socket
    if os.path.exists('/var/run/docker.sock'):
        indicators.append('[CRITICAL] Docker socket mounted - full host access possible')
    # Privileged mode
    try:
        with open('/proc/1/status', 'r') as f:
            for line in f:
                if 'CapEff' in line:
                    caps = int(line.split(':')[1].strip(), 16)
                    if caps == 0x3fffffffff:
                        indicators.append('[CRITICAL] Privileged container - all capabilities')
    except: pass
    # Host PID namespace
    try:
        procs = os.listdir('/proc')
        if len([p for p in procs if p.isdigit()]) > 50:
            indicators.append('[HIGH] Possible host PID namespace')
    except: pass
    # Host mounts
    try:
        with open('/proc/mounts', 'r') as f:
            for line in f:
                if '/host' in line or 'ext4' in line:
                    indicators.append(f'[HIGH] Host filesystem mount: {line.strip()[:100]}')
    except: pass
    # Service account token
    sa_path = '/var/run/secrets/kubernetes.io/serviceaccount/token'
    if os.path.exists(sa_path):
        indicators.append('[MEDIUM] K8s service account token available')
    return indicators

print('=== Container Escape Checker ===')
results = check_container()
for r in results:
    print(f'  {r}')
if not results:
    print('  No escape vectors found')

