import subprocess
import json
import sys

def kubectl(args):
    cmd = ['kubectl'] + args + ['-o', 'json']
    try:
        result = subprocess.run(cmd, capture_output=True, text=True, timeout=15)
        if result.returncode == 0:
            return json.loads(result.stdout)
    except: pass
    return None

print('=== Kubernetes Enumerator ===')

# Current context
try:
    result = subprocess.run(['kubectl', 'config', 'current-context'], capture_output=True, text=True)
    print(f'Context: {result.stdout.strip()}')
except: print('kubectl not found')

# Namespaces
ns = kubectl(['get', 'namespaces'])
if ns:
    print(f'\nNamespaces: {len(ns.get("items", []))}')
    for n in ns['items']: print(f'  {n["metadata"]["name"]}')

# Pods
pods = kubectl(['get', 'pods', '--all-namespaces'])
if pods:
    print(f'\nPods: {len(pods.get("items", []))}')
    for p in pods['items'][:15]:
        ns_name = p['metadata']['namespace']
        pod_name = p['metadata']['name']
        phase = p['status'].get('phase', 'Unknown')
        print(f'  {ns_name:20s} {pod_name:40s} {phase}')

# Secrets
secrets = kubectl(['get', 'secrets', '--all-namespaces'])
if secrets:
    print(f'\nSecrets: {len(secrets.get("items", []))}')
    for s in secrets['items'][:10]:
        print(f'  {s["metadata"]["namespace"]:20s} {s["metadata"]["name"]}')
